/* Core BPNN functions translated from CUDA to OpenMP */

void bpnn_layerforward(float *l1, float *l2, float **conn, int n1, int n2) {
  float sum;
  int j, k;

  l1[0] = 1.0;

  #pragma omp parallel for private(j, k, sum) shared(l1, l2, conn, n1, n2)
  for (j = 1; j <= n2; j++) {
    sum = 0.0;
    for (k = 0; k <= n1; k++) {	
      sum += conn[k][j] * l1[k]; 
    }
    l2[j] = squash(sum);
  }
}

void bpnn_output_error(float *delta, float *target, float *output, int nj, float *err) {
  int j;
  float o, t, errsum;
  errsum = 0.0;
  for (j = 1; j <= nj; j++) {
    o = output[j];
    t = target[j];
    delta[j] = o * (1.0 - o) * (t - o);
    errsum += ABS(delta[j]);
  }
  *err = errsum;
}

void bpnn_hidden_error(float *delta_h, int nh, float *delta_o, int no, float **who, float *hidden, float *err) {
  int j, k;
  float h, sum, errsum;

  errsum = 0.0;
  for (j = 1; j <= nh; j++) {
    h = hidden[j];
    sum = 0.0;
    for (k = 1; k <= no; k++) {
      sum += delta_o[k] * who[j][k];
    }
    delta_h[j] = h * (1.0 - h) * sum;
    errsum += ABS(delta_h[j]);
  }
  *err = errsum;
}

void bpnn_adjust_weights(float *delta, int ndelta, float *ly, int nly, float **w, float **oldw) {
  float new_dw;
  int k, j;

  ly[0] = 1.0;

  #pragma omp parallel for private(j, k, new_dw) shared(delta, ly, w, oldw, ndelta, nly)
  for (j = 1; j <= ndelta; j++) {
    for (k = 0; k <= nly; k++) {
      new_dw = ((ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k][j]));
      w[k][j] += new_dw;
      oldw[k][j] = new_dw;
    }
  }
}

/* Main training function replacing the CUDA version */
void bpnn_train_cuda(BPNN *net, float *eo, float *eh) {
  int in, hid, out;
  float out_err, hid_err;

  in = net->input_n;
  hid = net->hidden_n;
  out = net->output_n;   

  int m = 0;
  float *input_weights_one_dim;
  float *input_weights_prev_one_dim;
  float *partial_sum;
  float sum;

  int num_blocks = in / 16;  

  input_weights_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
  input_weights_prev_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
  partial_sum = (float *) malloc(num_blocks * WIDTH * sizeof(float));

  for (int k = 0; k <= in; k++) {	
    for (int j = 0; j <= hid; j++) {
      input_weights_one_dim[m] = net->input_weights[k][j];
      input_weights_prev_one_dim[m] = net->input_prev_weights[k][j];
      m++;
    }
  }

  printf("Performing CPU computation\n");

  // Simulate bpnn_layerforward_CUDA using OpenMP
  // Reset partial_sum
  for(int i=0; i < num_blocks * WIDTH; i++) partial_sum[i] = 0.0f;

  // Parallelize the computation of partial sums
  #pragma omp parallel for reduction(+:partial_sum[0:num_blocks*WIDTH])
  for (int by = 0; by < num_blocks; by++) {
    for (int ty = 0; ty < HEIGHT; ty++) {
      int index_in = HEIGHT * by + ty + 1;
      if (index_in > in) continue;

      float input_node = net->input_units[index_in];

      for (int tx = 0; tx < WIDTH; tx++) {
        int j = ty + 1; 
        if (j > hid) continue;

        int k_global = by * HEIGHT + ty;
        if (k_global <= in) {
           partial_sum[by * hid + (j-1)] += net->input_weights[k_global][j] * input_node;
        }
      }
    }
  }

  // Aggregate partial sums and compute hidden units
  for (int j = 1; j <= hid; j++) {
    sum = 0.0;
    for (int k = 0; k < num_blocks; k++) {	
      sum += partial_sum[k * hid + j-1];
    }
    sum += net->input_weights[0][j]; 
    net->hidden_units[j] = squash(sum);
  }

  bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
  bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
  bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);  
  bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);

  bpnn_adjust_weights(net->hidden_delta, hid, net->input_units, in, net->input_weights, net->input_prev_weights);

  free(partial_sum);
  free(input_weights_one_dim);
  free(input_weights_prev_one_dim);
}

