            ori_col = col + common.in2_sub_cumh_sel_collow - 1;
            unique[bx].d_in2_sub_cumh_sel[ei_new] = unique[bx].d_in2_sub_cumh[ori_col*common.in2_sub_cumh_rows+ori_row];
