            ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
            ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
            unique[bx].d_in2_sub2[ei_new] = unique[bx].d_in2_sub_cumh[ori_col*common.in2_sub_cumh_rows+ori_row];
        }

        for(ei_new = 0; ei_new < common.in2_sub2_elem; ei_new++) {
            unique[bx].d_in2_sub2[ei_new] = unique[bx].d_in2_sub_cumh_sel[ei_new] - unique[bx].d_in2_sub2[ei_new];
        }

        for(ei_new = 0; ei_new < common.in2_sqr_elem; ei_new++) {
            temp = unique[bx].d_in2[ei_new];
            unique[bx].d_in2_sqr[ei_new] = temp * temp;
        }

        for(ei_new = 0; ei_new < common.in2_pad_cumv_elem; ei_new++) {
            row = (ei_new+1) % common.in2_pad_cumv_rows - 1;
            col = (ei_new+1) / common.in2_pad_cumv_rows + 1 - 1;
            if((ei_new+1) % common.in2_pad_cumv_rows == 0){
                row = common.in2_pad_cumv_rows - 1;
                col = col-1;
