            ori_col = col + common.in2_pad_cumv_sel_collow - 1;
            unique[bx].d_in2_pad_cumv_sel[ei_new] = unique[bx].d_in2_pad_cumv[ori_col*common.in2_pad_cumv_rows+ori_row];
