void lud_diagonal_omp(float *m, int matrix_dim, int offset)
{
  int i, j;
  float shadow[BLOCK_SIZE][BLOCK_SIZE];

  int array_offset = offset*matrix_dim+offset;

  // Load diagonal block into shadow
  for(i=0; i < BLOCK_SIZE; i++){
    for(int t=0; t < BLOCK_SIZE; t++){
      shadow[i][t] = m[array_offset+t];
    }
    array_offset += matrix_dim;
  }

  // Process diagonal block
  for(i=0; i < BLOCK_SIZE-1; i++) {
    // Update lower part of column i
    for(int t=i+1; t < BLOCK_SIZE; t++){
      float sum = 0.0f;
      for(j=0; j < i; j++)
        sum += shadow[t][j]*shadow[j][i];
      shadow[t][i] -= sum;
      shadow[t][i] /= shadow[i][i];
    }

    // Update row i+1
    for(int t=0; t < BLOCK_SIZE; t++){
      float sum = 0.0f;
      for(j=0; j < i+1; j++)
        sum += shadow[i+1][j]*shadow[j][t];
      shadow[i+1][t] -= sum;
    }
  }

  // Write back results
  array_offset = (offset+1)*matrix_dim+offset;
  for(i=1; BLOCK_SIZE > i; i++){
    for(int t=0; t < BLOCK_SIZE; t++){
      m[array_offset+t] = shadow[i][t];
    }
    array_offset += matrix_dim;
  }
}

void lud_perimeter_omp(float *m, int matrix_dim, int offset)
{
  float dia[BLOCK_SIZE][BLOCK_SIZE];
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];

  int i, j, array_offset;
  int idx;

  // Load diagonal and perimeter data
  for (idx = 0; idx < BLOCK_SIZE; idx++) {
    array_offset = offset*matrix_dim+offset;
    for (i=0; i < BLOCK_SIZE/2; i++){
      dia[i][idx]=m[array_offset+idx];
      array_offset += matrix_dim;
    }

    array_offset = offset*matrix_dim+offset;
    for (i=0; i < BLOCK_SIZE; i++) {
      peri_row[i][idx]=m[array_offset+(idx+1)*BLOCK_SIZE+idx];
      array_offset += matrix_dim;
    }
  }

  for (idx = 0; idx < BLOCK_SIZE; idx++) {
    array_offset = (offset+BLOCK_SIZE/2)*matrix_dim+offset;
    for (i=BLOCK_SIZE/2; i < BLOCK_SIZE; i++){
      dia[i][idx]=m[array_offset+idx];
      array_offset += matrix_dim;
    }

    array_offset = (offset+(idx+1)*BLOCK_SIZE)*matrix_dim+offset;
    for (i=0; i < BLOCK_SIZE; i++) {
      peri_col[idx][i] = m[array_offset+idx];
      array_offset += matrix_dim;
    }
  }

  // Update peri_row
  for (idx=0; idx < BLOCK_SIZE; idx++) {
    for(i=1; i < BLOCK_SIZE; i++){
      float sum = 0.0f;
      for (j=0; j < i; j++)
        sum += dia[i][j]*peri_row[j][idx];
      peri_row[i][idx] -= sum;
    }
  }

  // Update peri_col
  for (idx=0; idx < BLOCK_SIZE; idx++) {
    for(i=0; i < BLOCK_SIZE; i++){
      float sum = 0.0f;
      for(j=0; j < i; j++)
        sum += peri_col[idx][j]*dia[j][i];
      peri_col[idx][i] -= sum;
      peri_col[idx][i] /= dia[i][i];
    }
  }

  // Write back peri_row
  for (idx=0; idx < BLOCK_SIZE; idx++) {
    array_offset = (offset+1)*matrix_dim+offset;
    for(i=1; i < BLOCK_SIZE; i++){
      m[array_offset+(idx+1)*BLOCK_SIZE+idx] = peri_row[i][idx];
      array_offset += matrix_dim;
    }
  }

  // Write back peri_col
  for (idx=0; idx < BLOCK_SIZE; idx++) {
    array_offset = (offset+(idx+1)*BLOCK_SIZE)*matrix_dim+offset;
    for(i=0; i < BLOCK_SIZE; i++){
      m[array_offset+idx] = peri_col[i][idx];
      array_offset += matrix_dim;
    }
  }
}

void lud_internal_omp(float *m, int matrix_dim, int offset)
{
  int i, bx, by;
  int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

  for (by = 0; by < num_blocks; by++) {
    for (bx = 0; bx < num_blocks; bx++) {
      float peri_row[BLOCK_SIZE][BLOCK_SIZE];
      float peri_col[BLOCK_SIZE][BLOCK_SIZE];
      float sum;

      int global_row_id = offset + (by+1)*BLOCK_SIZE;
      int global_col_id = offset + (bx+1)*BLOCK_SIZE;

      // Load data
      for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
          peri_row[ty][tx] = m[(offset+ty)*matrix_dim+global_col_id+tx];
          peri_col[ty][tx] = m[(global_row_id+ty)*matrix_dim+offset+tx];
        }
      }

      // Compute and update
      for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
          sum = 0.0f;
          for (i=0; i < BLOCK_SIZE; i++)
            sum += peri_col[ty][i] * peri_row[i][tx];
          m[(global_row_id+ty)*matrix_dim+global_col_id+tx] -= sum;
        }
      }
    }
  }
}

void lud_omp(float *m, int matrix_dim)
{
