#endif


#else
#if REORDER_REF
		size_t refpitch;

		CUDA_MALLOC_PITCH( (void**)(&ref->d_ref_array),
		                                 &refpitch,
		                                 ref->pitch * sizeof(char),
		                                 numrows);
