	}
	stopTimer(ktimer);

	float ktime = getTimerValue(ktimer);
	ctx->statistics.t_match_kernel += ktime;
	fprintf(stderr, "match kernel time= %f\n", ktime);
	deleteTimer(ktimer);

	getMatchResults(ctx, page->id);
	unloadResultBuffer(ctx);    
