int matchSubset(MatchContext* ctx,
                ReferencePage* page) 
{

    loadQueries(ctx);

    fprintf(stderr, 
			"Matching queries %s - %s against ref coords %d - %d\n",
			ctx->queries->h_names[0], 
			ctx->queries->h_names[ctx->queries->count - 1],
