                ctx->min_match_length);
    }
    else {
        mummergpuKernel <<< dimGrid, dimBlock, 0 >>> (ctx->results.d_match_coords,
#if COALESCED_QUERIES
                ctx->results.d_coord_tex_array,
#endif

#if !QRYTEX
#if COALESCED_QUERIES
                (int*)
#endif
                ctx->queries->d_tex_array,
#endif

#if !NODETEX
                (_PixelOfNode*)(ctx->ref->d_node_tex_array),
