    dPb2 = 1e-3*(rcnCKib2 - rcnCKb2b + rcnCKt2b2); dPb = 1e-3*(rcnCKib + rcnCKb2b - rcnCKbt); dPt = 1e-3*(rcnCKbt-rcnCKta-rcnCKtt2); dPt2 = 1e-3*(rcnCKtt2-rcnCKt2a-rcnCKt2b2); dPa = 1e-3*(rcnCKta+rcnCKt2a-rcnCKai);
    dCa4CaN = 1e-3*(rcnCa4CaN - rcn0CaN - rcn2CaN - rcn4CaN); dCaMCa4CaN = 1e-3*(rcn0CaN - rcn02CaN); dCa2CaMCa4CaN = 1e-3*(rcn2CaN+rcn02CaN-rcn24CaN); dCa4CaMCa4CaN = 1e-3*(rcn4CaN+rcn24CaN);
    d_finavalu[offset_1] = dCaM; d_finavalu[offset_2] = dCa2CaM; d_finavalu[offset_3] = dCa4CaM; d_finavalu[offset_4] = dCaMB; d_finavalu[offset_5] = dCa2CaMB; d_finavalu[offset_6] = dCa4CaMB; d_finavalu[offset_7] = dPb2; d_finavalu[offset_8] = dPb; d_finavalu[offset_9] = dPt; d_finavalu[offset_10] = dPt2; d_finavalu[offset_11] = dPa; d_finavalu[offset_12] = dCa4CaN; d_finavalu[offset_13] = dCaMCa4CaN; d_finavalu[offset_14] = dCa2CaMCa4CaN; d_finavalu[offset_15] = dCa4CaMCa4CaN;
    d_finavalu[com_offset] = 1e-3*(2*CaMKIItot*(rcnCKtt2-rcnCKb2b) - 2*(rcn02+rcn24+rcn02B+rcn24B+rcnCa4CaN+rcn02CaN+rcn24CaN));
}

void kernel_fin_2(fp timeinst, fp* d_initvalu, fp* d_finavalu, int offset_ecc, int offset_Dyad, int offset_SL, int offset_Cyt, fp* d_params, fp* d_com) {
    fp BtotDyad, CaMKIItotDyad, Vmyo, Vdyad, VSL, kSLmyo, k0Boff, k0Bon, k2Boff, k2Bon, k4Bon, CaMtotDyad, Bdyad, J_cam_dyadSL, J_ca2cam_dyadSL, J_ca4cam_dyadSL, J_cam_SLmyo, J_ca2cam_SLmyo, J_ca4cam_SLmyo;
    BtotDyad = d_params[1]; CaMKIItotDyad = d_params[2];
    d_finavalu[offset_ecc+35] = d_finavalu[offset_ecc+35] + 1e-3*d_com[0];
    d_finavalu[offset_ecc+36] = d_finavalu[offset_ecc+36] + 1e-3*d_com[1];
    d_finavalu[offset_ecc+37] = d_finavalu[offset_ecc+37] + 1e-3*d_com[2];
    Vmyo = 2.1454e-11; Vdyad = 1.7790e-14; VSL = 6.6013e-13; kSLmyo = 8.587e-15; k0Boff = 0.0014; k0Bon = k0Boff/0.2; k2Boff = k0Boff/100; k2Bon = k0Bon; k4Bon = k0Bon;
    CaMtotDyad = d_initvalu[offset_Dyad+0] + d_initvalu[offset_Dyad+1] + d_initvalu[offset_Dyad+2] + d_initvalu[offset_Dyad+3] + d_initvalu[offset_Dyad+4] + d_initvalu[offset_Dyad+5] + CaMKIItotDyad * (d_initvalu[offset_Dyad+6] + d_initvalu[offset_Dyad+7] + d_initvalu[offset_Dyad+8] + d_initvalu[offset_Dyad+9]) + d_initvalu[offset_Dyad+12] + d_initvalu[offset_Dyad+13] + d_initvalu[offset_Dyad+14];
    Bdyad = BtotDyad - CaMtotDyad;
    J_cam_dyadSL = 1e-3 * (k0Boff*d_initvalu[offset_Dyad+0] - k0Bon*Bdyad*d_initvalu[offset_SL+0]);
    J_ca2cam_dyadSL = 1e-3 * (k2Boff*d_initvalu[offset_Dyad+1] - k2Bon*Bdyad*d_initvalu[offset_SL+1]);
    J_ca4cam_dyadSL = 1e-3 * (k2Boff*d_initvalu[offset_Dyad+2] - k4Bon*Bdyad*d_initvalu[offset_SL+2]);
    J_cam_SLmyo = kSLmyo * (d_initvalu[offset_SL+0] - d_initvalu[offset_Cyt+0]);
    J_ca2cam_SLmyo = kSLmyo * (d_initvalu[offset_SL+1] - d_initvalu[offset_Cyt+1]);
    J_ca4cam_SLmyo = kSLmyo * (d_initvalu[offset_SL+2] - d_initvalu[offset_Cyt+2]);
    d_finavalu[offset_Dyad+0] = d_finavalu[offset_Dyad+0] - J_cam_dyadSL;
    d_finavalu[offset_Dyad+1] = d_finavalu[offset_Dyad+1] - J_ca2cam_dyadSL;
    d_finavalu[offset_Dyad+2] = d_finavalu[offset_Dyad+2] - J_ca4cam_dyadSL;
    d_finavalu[offset_SL+0] = d_finavalu[offset_SL+0] + J_cam_dyadSL*Vdyad/VSL - J_cam_SLmyo/VSL;
    d_finavalu[offset_SL+1] = d_finavalu[offset_SL+1] + J_ca2cam_dyadSL*Vdyad/VSL - J_ca2cam_SLmyo/VSL;
    d_finavalu[offset_SL+2] = d_finavalu[offset_SL+2] + J_ca4cam_dyadSL*Vdyad/VSL - J_ca4cam_SLmyo/VSL;
