    d_finavalu[offset_Cyt+2] = d_finavalu[offset_Cyt+2] + J_ca4cam_SLmyo/Vmyo;
}

void kernel_2(fp timeinst, fp* initvalu, fp* params, fp* finavalu, fp* com) {
    int valu_offset_ecc, valu_offset_Dyad, valu_offset_SL, valu_offset_Cyt, params_offset_Dyad, params_offset_SL, params_offset_Cyt, com_offset_Dyad, com_offset_SL, com_offset_Cyt, i;
