    const fp b10_4 = 23.0 / 108.0;
    const fp b10_5 = -976.0 / 135.0;
    const fp b10_6 = 311.0 / 54.0;
    const fp b10_7 = -19.0 / 60.0;
    const fp b10_8 = 17.0 / 6.0;
    const fp b10_9 = -1.0 / 12.0;
    const fp b11_1 = 2383.0 / 4100.0;
    const fp b11_4 = -341.0 / 164.0;
    const fp b11_5 = 4496.0 / 1025.0;
    const fp b11_6 = -301.0 / 82.0;
    const fp b11_7 = 2133.0 / 4100.0;
    const fp b11_8 = 45.0 / 82.0;
    const fp b11_9 = 45.0 / 164.0;
    const fp b11_10 = 18.0 / 41.0;
    const fp b12_1 = 3.0 / 205.0;
    const fp b12_6 = - 6.0 / 41.0;
    const fp b12_7 = - 3.0 / 205.0;
    const fp b12_8 = - 3.0 / 41.0;
    const fp b12_9 = 3.0 / 41.0;
    const fp b12_10 = 6.0 / 41.0;
    const fp b13_1 = -1777.0 / 4100.0;
    const fp b13_4 = -341.0 / 164.0;
    const fp b13_5 = 4496.0 / 1025.0;
    const fp b13_6 = -289.0 / 82.0;
    const fp b13_7 = 2193.0 / 4100.0;
    const fp b13_8 = 51.0 / 82.0;
    const fp b13_9 = 33.0 / 164.0;
    const fp b13_10 = 12.0 / 41.0;
    const fp err_factor  = -41.0 / 840.0;
    fp h2_7 = a2 * h;
    fp timeinst_temp;
    int i,j;
    for(j=0; j<13; j++){
        if(j==0){ timeinst_temp = timeinst; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i]; } }
        else if(j==1){ timeinst_temp = timeinst+h2_7; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h2_7 * (finavalu_temp[0*EQUATIONS+i]); } }
        else if(j==2){ timeinst_temp = timeinst+a3*h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b31*finavalu_temp[0*EQUATIONS+i] + b32*finavalu_temp[1*EQUATIONS+i]); } }
        else if(j==3){ timeinst_temp = timeinst+a4*h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b41*finavalu_temp[0*EQUATIONS+i] + b43*finavalu_temp[2*EQUATIONS+i]) ; } }
        else if(j==4){ timeinst_temp = timeinst+a5*h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b51*finavalu_temp[0*EQUATIONS+i] + b53*finavalu_temp[2*EQUATIONS+i] + b54*finavalu_temp[3*EQUATIONS+i]) ; } }
        else if(j==5){ timeinst_temp = timeinst+a6*h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b61*finavalu_temp[0*EQUATIONS+i] + b64*finavalu_temp[3*EQUATIONS+i] + b65*finavalu_temp[4*EQUATIONS+i]) ; } }
        else if(j==6){ timeinst_temp = timeinst+a7*h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b71*finavalu_temp[0*EQUATIONS+i] + b74*finavalu_temp[3*EQUATIONS+i] + b75*finavalu_temp[4*EQUATIONS+i] + b76*finavalu_temp[5*EQUATIONS+i]); } }
        else if(j==7){ timeinst_temp = timeinst+a8*h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b81*finavalu_temp[0*EQUATIONS+i] + b85*finavalu_temp[4*EQUATIONS+i] + b86*finavalu_temp[5*EQUATIONS+i] + b87*finavalu_temp[6*EQUATIONS+i]); } }
        else if(j==8){ timeinst_temp = timeinst+a9*h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b91*finavalu_temp[0*EQUATIONS+i] + b94*finavalu_temp[3*EQUATIONS+i] + b95*finavalu_temp[4*EQUATIONS+i] + b96*finavalu_temp[5*EQUATIONS+i] + b97*finavalu_temp[6*EQUATIONS+i]+ b98*finavalu_temp[7*EQUATIONS+i]) ; } }
        else if(j==9){ timeinst_temp = timeinst+a10*h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b10_1*finavalu_temp[0*EQUATIONS+i] + b10_4*finavalu_temp[3*EQUATIONS+i] + b10_5*finavalu_temp[4*EQUATIONS+i] + b10_6*finavalu_temp[5*EQUATIONS+i] + b10_7*finavalu_temp[6*EQUATIONS+i] + b10_8*finavalu_temp[7*EQUATIONS+i] + b10_9*finavalu_temp[8*EQUATIONS+i]) ; } }
        else if(j==10){ timeinst_temp = timeinst+h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b11_1*finavalu_temp[0*EQUATIONS+i] + b11_4*finavalu_temp[3*EQUATIONS+i] + b11_5*finavalu_temp[4*EQUATIONS+i] + b11_6*finavalu_temp[5*EQUATIONS+i] + b11_7*finavalu_temp[6*EQUATIONS+i] + b11_8*finavalu_temp[7*EQUATIONS+i] + b11_9*finavalu_temp[8*EQUATIONS+i]+ b11_10 * finavalu_temp[9*EQUATIONS+i]); } }
        else if(j==11){ timeinst_temp = timeinst; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b12_1*finavalu_temp[0*EQUATIONS+i] + b12_6*finavalu_temp[5*EQUATIONS+i] + b12_7*finavalu_temp[6*EQUATIONS+i] + b12_8*finavalu_temp[7*EQUATIONS+i] + b12_9*finavalu_temp[8*EQUATIONS+i] + b12_10 * finavalu_temp[9*EQUATIONS+i]) ; } }
        else if(j==12){ timeinst_temp = timeinst+h; for(i=0; i<EQUATIONS; i++){ initvalu_temp[i] = initvalu[i] + h * ( b13_1*finavalu_temp[0*EQUATIONS+i] + b13_4*finavalu_temp[3*EQUATIONS+i] + b13_5*finavalu_temp[4*EQUATIONS+i] + b13_6*finavalu_temp[5*EQUATIONS+i] + b13_7*finavalu_temp[6*EQUATIONS+i] + b13_8*finavalu_temp[7*EQUATIONS+i] + b13_9*finavalu_temp[8*EQUATIONS+i] + b13_10*finavalu_temp[9*EQUATIONS+i] + finavalu_temp[11*EQUATIONS+i]) ; } }
        kernel_2(timeinst_temp, initvalu_temp, parameter, &finavalu_temp[j*EQUATIONS], com);
    }
    for(i=0; i<EQUATIONS; i++){ finavalu[i]= initvalu[i] +  h * (c_1_11 * (finavalu_temp[0*EQUATIONS+i] + finavalu_temp[10*EQUATIONS+i])  + c6 * finavalu_temp[5*EQUATIONS+i] + c_7_8 * (finavalu_temp[6*EQUATIONS+i] + finavalu_temp[7*EQUATIONS+i]) + c_9_10 * (finavalu_temp[8*EQUATIONS+i] + finavalu_temp[9*EQUATIONS+i]) ); }
    for(i=0; i<EQUATIONS; i++){ error[i] = fabs(err_factor * (finavalu_temp[0*EQUATIONS+i] + finavalu_temp[10*EQUATIONS+i] - finavalu_temp[11*EQUATIONS+i] - finavalu_temp[12*EQUATIONS+i])); }
}

void solver_2(int workload, int xmax, fp* x, fp* y, fp* params, fp* com, fp* err, fp* scale, fp* yy, fp* initvalu_temp, fp* finavalu_temp) {
    fp err_exponent;
    fp h_init;
    fp h;
    fp tolerance;
    int xmin;
    int error;
    int outside;
    fp scale_min;
    fp scale_fina;
    int i, j, k;
    long y_pointer_initial;
    long y_pointer_current;
    long x_pointer_current;
    int err_pointer;
    int scale_pointer;
    int yy_pointer;
    int params_pointer;
    int initvalu_temp_pointer;
    int finavalu_temp_pointer;
    int com_pointer;
    int tid;
    #pragma omp parallel for
    for(tid = 0; tid < workload; tid++) {
        err_pointer = tid*EQUATIONS;
        scale_pointer = tid*EQUATIONS;
        yy_pointer = tid*EQUATIONS;
        params_pointer = tid*PARAMETERS;
        initvalu_temp_pointer = tid*EQUATIONS;
        finavalu_temp_pointer = tid*13*EQUATIONS;
        com_pointer = tid*3;
        err_exponent = 1.0 / 7.0;
        h_init = 1;
        h = h_init;
        xmin = 0;
        tolerance = 10 / (fp)(xmax - xmin);
        if (xmax < xmin || h <= 0.0){ continue; }
        if (xmax == xmin){ continue; }
        if (h > (xmax - xmin) ) { h = (fp)xmax - (fp)xmin; }
        for(k=1; k<(xmax+1); k++) {
            y_pointer_initial = tid*((xmax+1)*EQUATIONS)+(k-1)*EQUATIONS;
            y_pointer_current = tid*((xmax+1)*EQUATIONS)+k*EQUATIONS;
            x_pointer_current = tid*(xmax+1)+k;
            x[x_pointer_current] = (fp)k;
            h = h_init;
            scale_fina = 1.0;
            for (j = 0; j < ATTEMPTS; j++) {
                error = 0;
                outside = 0;
                scale_min = MAX_SCALE_FACTOR;
                embedded_fehlberg_7_8_2(h, x[x_pointer_current], &y[y_pointer_initial], &y[y_pointer_current], &params[params_pointer], &err[err_pointer], &initvalu_temp[initvalu_temp_pointer], &finavalu_temp[finavalu_temp_pointer], &com[com_pointer]);
                for(i=0; i<EQUATIONS; i++){ if(0 < err[err_pointer+i]){ error = 1; } }
                if (error != 1) { scale_fina = MAX_SCALE_FACTOR; break; }
                for(i=0; i<EQUATIONS; i++){
                    if(y[y_pointer_initial+i] == 0.0){ yy[yy_pointer+i] = tolerance; } else { yy[yy_pointer+i] = fabs(y[y_pointer_initial+i]); }
                    scale[scale_pointer+i] = 0.8 * pow( tolerance * yy[yy_pointer+i] / err[err_pointer+i] , err_exponent );
                    if(scale[scale_pointer+i]<scale_min){ scale_min = scale[scale_pointer+i]; }
                }
                scale_fina = min( max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);
                for(i=0; i<EQUATIONS; i++){ if ( err[err_pointer+i] > ( tolerance * yy[yy_pointer+i] ) ){ outside = 1; } }
                if (outside == 0){ break; }
                h = h * scale_fina;
                if (h >= 0.9) { h = 0.9; }
                if ( x[x_pointer_current] + h > (fp)xmax ){ h = (fp)xmax - x[x_pointer_current]; }
                else if ( x[x_pointer_current] + h + 0.5 * h > (fp)xmax ){ h = 0.5 * h; }
            }
            x[x_pointer_current] = x[x_pointer_current] + h;
            if ( j >= ATTEMPTS ) { continue; }
        }
    }
}

int work_2(int xmax, int workload){
    long long time0, time1, time2, time3, time4, time5, time6;
    time0 = get_time();
    long memory;
    int i;
    int pointer;
    fp* y; fp* d_y; long y_mem;
    fp* x; fp* d_x; long x_mem;
    fp* params; fp* d_params; int params_mem;
    fp* d_com; int com_mem;
    fp* d_err; int err_mem;
