    fp* d_yy; int yy_mem;
    fp* d_initvalu_temp; int initvalu_temp_mem;
    fp* d_finavalu_temp; int finavalu_temp_mem;
    time1 = get_time();
    memory = workload*(xmax+1)*EQUATIONS*4;
    if(memory>1000000000){ printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n"); return 0; }
    y_mem = workload * (xmax+1) * EQUATIONS * sizeof(fp);
    y= (fp *) malloc(y_mem); d_y = (fp *) malloc(y_mem);
    x_mem = workload * (xmax+1) * sizeof(fp);
    x= (fp *) malloc(x_mem); d_x = (fp *) malloc(x_mem);
