	I_Na_tot_sl = I_Na_sl+I_nabk_sl+3*I_ncx_sl+3*I_nak_sl+I_CaNa_sl;
	d_finavalu[offset_32] = -I_Na_tot_junc*Cmem/(Vjunc*Frdy)+J_na_juncsl/Vjunc*(d_initvalu_33-d_initvalu_32)-d_finavalu[offset_17];
	oneovervsl = 1/Vsl;
	d_finavalu[offset_33] = -I_Na_tot_sl*Cmem*oneovervsl/Frdy+J_na_juncsl*oneovervsl*(d_initvalu_32-d_initvalu_33)+J_na_slmyo*oneovervsl*(d_initvalu_34-d_initvalu_33)-d_finavalu[offset_18];
	d_finavalu[offset_34] = J_na_slmyo/Vmyo*(d_initvalu_33-d_initvalu_34);

	I_K_tot = I_to+I_kr+I_ks+I_ki-2*I_nak+I_CaK+I_kp;
	d_finavalu[offset_35] = 0;

	I_Ca_tot_junc = I_Ca_junc+I_cabk_junc+I_pca_junc-2*I_ncx_junc;
	I_Ca_tot_sl = I_Ca_sl+I_cabk_sl+I_pca_sl-2*I_ncx_sl;
	d_finavalu[offset_36] = -I_Ca_tot_junc*Cmem/(Vjunc*2*Frdy)+J_ca_juncsl/Vjunc*(d_initvalu_37-d_initvalu_36)
	         - J_CaB_junction+(J_SRCarel)*Vsr/Vjunc+J_SRleak*Vmyo/Vjunc;
	d_finavalu[offset_37] = -I_Ca_tot_sl*Cmem/(Vsl*2*Frdy)+J_ca_juncsl/Vsl*(d_initvalu_36-d_initvalu_37)
	         + J_ca_slmyo/Vsl*(d_initvalu_38-d_initvalu_37)-J_CaB_sl;
	d_finavalu[offset_38] = -J_serca-J_CaB_cytosol +J_ca_slmyo/Vmyo*(d_initvalu_37-d_initvalu_38);

	state = 1;
	switch(state){
		case 0:
			I_app = 0;
			break;
		case 1:
			if(fmod(timeinst,cycleLength) <= 5){
				I_app = 9.5;
			}
			else{
				I_app = 0.0;
			}
			break;
		case 2:
			V_hold = -55;
			V_test = 0;
			if(timeinst>0.5 && timeinst<200.5){
				V_clamp = V_test;
			}
			else{
				V_clamp = V_hold;
			}
			R_clamp = 0.04;
			I_app = (V_clamp-d_initvalu_39)/R_clamp;
			break;
	}

	I_Na_tot = I_Na_tot_junc + I_Na_tot_sl;
	I_Cl_tot = I_ClCa+I_Clbk;
	I_Ca_tot = I_Ca_tot_junc+I_Ca_tot_sl;
	I_tot = I_Na_tot+I_Cl_tot+I_Ca_tot+I_K_tot;
	d_finavalu[offset_39] = -(I_tot-I_app);

	d_finavalu[offset_41] = 0;
	d_finavalu[offset_42] = 0;
}

void kernel_cam(	fp timeinst,
					fp* d_initvalu,
					fp* d_finavalu,
					int valu_offset,
					fp* d_params,
					int params_offset,
					fp* d_com,
					int com_offset,
					fp Ca){

	fp Btot, CaMKIItot, CaNtot, PP1tot, K, Mg;
	int offset_1, offset_2, offset_3, offset_4, offset_5, offset_6, offset_7, offset_8, offset_9, offset_10;
	int offset_11, offset_12, offset_13, offset_14, offset_15;
	fp CaM, Ca2CaM, Ca4CaM, CaMB, Ca2CaMB, Ca4CaMB, Pb2, Pb, Pt, Pt2, Pa;
	fp Ca4CaN, CaMCa4CaN, Ca2CaMCa4CaN, Ca4CaMCa4CaN;
	fp Kd02, Kd24, k20, k02, k42, k24;
	fp k0Boff, k0Bon, k2Boff, k2Bon, k4Boff, k4Bon;
	fp k20B, k02B, k42B, k24B;
	fp kbi, kib, kpp1, Kmpp1, kib2, kb2i, kb24, kb42, kta, kat, kt42, kt24, kat2, kt2a;
	fp kcanCaoff, kcanCaon, kcanCaM4on, kcanCaM4off, kcanCaM2on, kcanCaM2off, kcanCaM0on, kcanCaM0off;
	fp k02can, k20can, k24can, k42can;
	fp rcn02, rcn24;
	fp B, rcn02B, rcn24B, rcn0B, rcn2B, rcn4B;
	fp Ca2CaN, rcnCa4CaN, rcn02CaN, rcn24CaN, rcn0CaN, rcn2CaN, rcn4CaN;
	fp Pix, rcnCKib2, rcnCKb2b, rcnCKib, T, kbt, rcnCKbt, rcnCKtt2, rcnCKta, rcnCKt2a, rcnCKt2b2, rcnCKai;
	fp dCaM, dCa2CaM, dCa4CaM, dCaMB, dCa2CaMB, dCa4CaMB;
	fp dPb2, dPb, dPt, dPt2, dPa;
	fp dCa4CaN, dCaMCa4CaN, dCa2CaMCa4CaN, dCa4CaMCa4CaN;

	Btot = d_params[params_offset+1];
	CaMKIItot = d_params[params_offset+2];
	CaNtot = d_params[params_offset+3];
	PP1tot = d_params[params_offset+4];
	K = d_params[16];
	Mg = d_params[17];

	offset_1 = valu_offset;
	offset_2 = valu_offset+1;
	offset_3 = valu_offset+2;
	offset_4 = valu_offset+3;
	offset_5 = valu_offset+4;
	offset_6 = valu_offset+5;
	offset_7 = valu_offset+6;
	offset_8 = valu_offset+7;
	offset_9 = valu_offset+8;
	offset_10 = valu_offset+9;
	offset_11 = valu_offset+10;
	offset_12 = valu_offset+11;
	offset_13 = valu_offset+12;
	offset_14 = valu_offset+13;
	offset_15 = valu_offset+14;

	CaM = d_initvalu[offset_1];
	Ca2CaM = d_initvalu[offset_2];
	Ca4CaM = d_initvalu[offset_3];
	CaMB = d_initvalu[offset_4];
	Ca2CaMB = d_initvalu[offset_5];
	Ca4CaMB = d_initvalu[offset_6];
	Pb2 = d_initvalu[offset_7];
	Pb = d_initvalu[offset_8];
	Pt = d_initvalu[offset_9];
	Pt2 = d_initvalu[offset_10];
	Pa = d_initvalu[offset_11];
	Ca4CaN = d_initvalu[offset_12];
	CaMCa4CaN = d_initvalu[offset_13];
	Ca2CaMCa4CaN = d_initvalu[offset_14];
	Ca4CaMCa4CaN = d_initvalu[offset_15];

	if (1 >= Mg){
		Kd02 = 0.0025*(1+K/0.94-Mg/0.012)*(1+K/8.1+Mg/0.022);
		Kd24 = 0.128*(1+K/0.64+Mg/0.0014)*(1+K/13.0-Mg/0.153);
	}
	else{
		Kd02 = 0.0025*(1+K/0.94-1/0.012+(Mg-1)/0.060)*(1+K/8.1+1/0.022+(Mg-1)/0.068);
		Kd24 = 0.128*(1+K/0.64+1/0.0014+(Mg-1)/0.005)*(1+K/13.0-1/0.153+(Mg-1)/0.150);
	}
	k20 = 10;
	k02 = k20/Kd02;
	k42 = 500;
	k24 = k42/Kd24;

	k0Boff = 0.0014;
	k0Bon = k0Boff/0.2;
	k2Boff = k0Boff/100;
	k2Bon = k0Bon;
	k4Boff = k2Boff;
	k4Bon = k0Bon;

	k20B = k20/100;
	k02B = k02;
	k42B = k42;
	k24B = k24;

	kbi = 2.2;
	kib = kbi/33.5e-3;
	kpp1 = 1.72;
	Kmpp1 = 11.5;
	kib2 = kib;
	kb2i = kib2*5;
	kb24 = k24;
	kb42 = k42*33.5e-3/5;
	kta = kbi/1000;
	kat = kib;
	kt42 = k42*33.5e-6/5;
	kt24 = k24;
	kat2 = kib;
	kt2a = kib*5;

	kcanCaoff = 1;
	kcanCaon = kcanCaoff/0.5;
	kcanCaM4on = 46;
	kcanCaM4off = 0.0013;
	kcanCaM2on = kcanCaM4on;
	kcanCaM2off = 2508*kcanCaM4off;
	kcanCaM0on = kcanCaM4on;
	kcanCaM0off = 165*kcanCaM2off;
	k02can = k02;
	k20can = k20/165;
	k24can = k24;
	k42can = k20/2508;

	rcn02 = k02*pow(Ca,2)*CaM - k20*Ca2CaM;
	rcn24 = k24*pow(Ca,2)*Ca2CaM - k42*Ca4CaM;

	B = Btot - CaMB - Ca2CaMB - Ca4CaMB;
	rcn02B = k02B*pow(Ca,2)*CaMB - k20B*Ca2CaMB;
	rcn24B = k24B*pow(Ca,2)*Ca2CaMB - k42B*Ca4CaMB;
	rcn0B = k0Bon*CaM*B - k0Boff*CaMB;
	rcn2B = k2Bon*Ca2CaM*B - k2Boff*Ca2CaMB;
	rcn4B = k4Bon*Ca4CaM*B - k4Boff*Ca4CaMB;

	Ca2CaN = CaNtot - Ca4CaN - CaMCa4CaN - Ca2CaMCa4CaN - Ca4CaMCa4CaN;
	rcnCa4CaN = kcanCaon*pow(Ca,2)*Ca2CaN - kcanCaoff*Ca4CaN;
	rcn02CaN = k02can*pow(Ca,2)*CaMCa4CaN - k20can*Ca2CaMCa4CaN;
	rcn24CaN = k24can*pow(Ca,2)*Ca2CaMCa4CaN - k42can*Ca4CaMCa4CaN;
	rcn0CaN = kcanCaM0on*CaM*Ca4CaN - kcanCaM0off*CaMCa4CaN;
	rcn2CaN = kcanCaM2on*Ca2CaM*Ca4CaN - kcanCaM2off*Ca2CaMCa4CaN;
	rcn4CaN = kcanCaM4on*Ca4CaM*Ca4CaN - kcanCaM4off*Ca4CaMCa4CaN;

	Pix = 1 - Pb2 - Pb - Pt - Pt2 - Pa;
	rcnCKib2 = kib2*Ca2CaM*Pix - kb2i*Pb2;
	rcnCKb2b = kb24*pow(Ca,2)*Pb2 - kb42*Pb;
	rcnCKib = kib*Ca4CaM*Pix - kbi*Pb;
	T = Pb + Pt + Pt2 + Pa;
	kbt = 0.055*T + 0.0074*pow(T,2) + 0.015*pow(T,3);
	rcnCKbt = kbt*Pb - kpp1*PP1tot*Pt/(Kmpp1+CaMKIItot*Pt);
	rcnCKtt2 = kt42*Pt - kt24*pow(Ca,2)*Pt2;
	rcnCKta = kta*Pt - kat*Ca4CaM*Pa;
	rcnCKt2a = kt2a*Pt2 - kat2*Ca2CaM*Pa;
	rcnCKt2b2 = kpp1*PP1tot*Pt2/(Kmpp1+CaMKIItot*Pt2);
	rcnCKai = kpp1*PP1tot*Pa/(Kmpp1+CaMKIItot*Pa);

	dCaM = 1e-3*(-rcn02 - rcn0B - rcn0CaN);
	dCa2CaM = 1e-3*(rcn02 - rcn24 - rcn2B - rcn2CaN + CaMKIItot*(-rcnCKib2 + rcnCKt2a) );
	dCa4CaM = 1e-3*(rcn24 - rcn4B - rcn4CaN + CaMKIItot*(-rcnCKib+rcnCKta) );
	dCaMB = 1e-3*(rcn0B-rcn02B);
	dCa2CaMB = 1e-3*(rcn02B + rcn2B - rcn24B);
	dCa4CaMB = 1e-3*(rcn24B + rcn4B);

	dPb2 = 1e-3*(rcnCKib2 - rcnCKb2b + rcnCKt2b2);
	dPb = 1e-3*(rcnCKib + rcnCKb2b - rcnCKbt);
	dPt = 1e-3*(rcnCKbt-rcnCKta-rcnCKtt2);
	dPt2 = 1e-3*(rcnCKtt2-rcnCKt2a-rcnCKt2b2);
	dPa = 1e-3*(rcnCKta+rcnCKt2a-rcnCKai);

	dCa4CaN = 1e-3*(rcnCa4CaN - rcn0CaN - rcn2CaN - rcn4CaN);
	dCaMCa4CaN = 1e-3*(rcn0CaN - rcn02CaN);
	dCa2CaMCa4CaN = 1e-3*(rcn2CaN+rcn02CaN-rcn24CaN);
	dCa4CaMCa4CaN = 1e-3*(rcn4CaN+rcn24CaN);

	d_finavalu[offset_1] = dCaM;
	d_finavalu[offset_2] = dCa2CaM;
	d_finavalu[offset_3] = dCa4CaM;
	d_finavalu[offset_4] = dCaMB;
	d_finavalu[offset_5] = dCa2CaMB;
	d_finavalu[offset_6] = dCa4CaMB;
	d_finavalu[offset_7] = dPb2;
	d_finavalu[offset_8] = dPb;
	d_finavalu[offset_9] = dPt;
	d_finavalu[offset_10] = dPt2;
	d_finavalu[offset_11] = dPa;
	d_finavalu[offset_12] = dCa4CaN;
	d_finavalu[offset_13] = dCaMCa4CaN;
	d_finavalu[offset_14] = dCa2CaMCa4CaN;
	d_finavalu[offset_15] = dCa4CaMCa4CaN;

	d_finavalu[com_offset] = 1e-3*(2*CaMKIItot*(rcnCKtt2-rcnCKb2b) - 2*(rcn02+rcn24+rcn02B+rcn24B+rcnCa4CaN+rcn02CaN+rcn24CaN));
}

void kernel_fin(	fp* initvalu,
					int initvalu_offset_ecc,
					int initvalu_offset_Dyad,
					int initvalu_offset_SL,
					int initvalu_offset_Cyt,
					fp* parameter,
					fp* finavalu,
					fp JCaDyad,
					fp JCaSL,
					fp JCaCyt){

	fp BtotDyad, CaMKIItotDyad;
	fp Vmyo, Vdyad, VSL;
	fp kSLmyo, k0Boff, k0Bon, k2Boff, k2Bon, k4Bon;
	fp CaMtotDyad, Bdyad;
	fp J_cam_dyadSL, J_ca2cam_dyadSL, J_ca4cam_dyadSL;
	fp J_cam_SLmyo, J_ca2cam_SLmyo, J_ca4cam_SLmyo;

	BtotDyad = parameter[2];
	CaMKIItotDyad = parameter[3];

	Vmyo = 2.1454e-11;
	Vdyad = 1.7790e-14;
	VSL = 6.6013e-13;

	kSLmyo = 8.587e-15;
	k0Boff = 0.0014;
	k0Bon = k0Boff/0.2;
	k2Boff = k0Boff/100;
	k2Bon = k0Bon;
	k4Bon = k0Bon;

	finavalu[initvalu_offset_ecc+35] = finavalu[initvalu_offset_ecc+35] + 1e-3*JCaDyad;
	finavalu[initvalu_offset_ecc+36] = finavalu[initvalu_offset_ecc+36] + 1e-3*JCaSL;
	finavalu[initvalu_offset_ecc+37] = finavalu[initvalu_offset_ecc+37] + 1e-3*JCaCyt;

	CaMtotDyad = initvalu[initvalu_offset_Dyad+0]
			   + initvalu[initvalu_offset_Dyad+1]
			   + initvalu[initvalu_offset_Dyad+2]
			   + initvalu[initvalu_offset_Dyad+3]
			   + initvalu[initvalu_offset_Dyad+4]
			   + initvalu[initvalu_offset_Dyad+5]
			   + CaMKIItotDyad * (  initvalu[initvalu_offset_Dyad+6]
								  + initvalu[initvalu_offset_Dyad+7]
								  + initvalu[initvalu_offset_Dyad+8]
								  + initvalu[initvalu_offset_Dyad+9])
			   + initvalu[initvalu_offset_Dyad+12]
			   + initvalu[initvalu_offset_Dyad+13]
			   + initvalu[initvalu_offset_Dyad+14];
	Bdyad = BtotDyad - CaMtotDyad;

	J_cam_dyadSL = 1e-3 * (  k0Boff*initvalu[initvalu_offset_Dyad+0] - k0Bon*Bdyad*initvalu[initvalu_offset_SL+0]);
	J_ca2cam_dyadSL = 1e-3 * (  k2Boff*initvalu[initvalu_offset_Dyad+1] - k2Bon*Bdyad*initvalu[initvalu_offset_SL+1]);
	J_ca4cam_dyadSL = 1e-3 * (  k2Boff*initvalu[initvalu_offset_Dyad+2] - k4Bon*Bdyad*initvalu[initvalu_offset_SL+2]);

	J_cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+0] - initvalu[initvalu_offset_Cyt+0]);
	J_ca2cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+1] - initvalu[initvalu_offset_Cyt+1]);
	J_ca4cam_SLmyo = kSLmyo * (  initvalu[initvalu_offset_SL+2] - initvalu[initvalu_offset_Cyt+2]);

	finavalu[initvalu_offset_Dyad+0] = finavalu[initvalu_offset_Dyad+0] - J_cam_dyadSL;
	finavalu[initvalu_offset_Dyad+1] = finavalu[initvalu_offset_Dyad+1] - J_ca2cam_dyadSL;
	finavalu[initvalu_offset_Dyad+2] = finavalu[initvalu_offset_Dyad+2] - J_ca4cam_dyadSL;

	finavalu[initvalu_offset_SL+0] = finavalu[initvalu_offset_SL+0] + J_cam_dyadSL*Vdyad/VSL - J_cam_SLmyo/VSL;
	finavalu[initvalu_offset_SL+1] = finavalu[initvalu_offset_SL+1] + J_ca2cam_dyadSL*Vdyad/VSL - J_ca2cam_SLmyo/VSL;
	finavalu[initvalu_offset_SL+2] = finavalu[initvalu_offset_SL+2] + J_ca4cam_dyadSL*Vdyad/VSL - J_ca4cam_SLmyo/VSL;

	finavalu[initvalu_offset_Cyt+0] = finavalu[initvalu_offset_Cyt+0] + J_cam_SLmyo/Vmyo;
	finavalu[initvalu_offset_Cyt+1] = finavalu[initvalu_offset_Cyt+1] + J_ca2cam_SLmyo/Vmyo;
	finavalu[initvalu_offset_Cyt+2] = finavalu[initvalu_offset_Cyt+2] + J_ca4cam_SLmyo/Vmyo;
}

void master(fp timeinst,
			fp* initvalu,
			fp* parameter,
			fp* finavalu,
			fp* com,
			fp* d_initvalu,
			fp* d_finavalu,
			fp* d_params,
			fp* d_com){

	int i;
	int initvalu_offset_ecc, initvalu_offset_Dyad, initvalu_offset_SL, initvalu_offset_Cyt;

	memcpy(d_initvalu, initvalu, EQUATIONS * sizeof(fp));
	memcpy(d_params, parameter, PARAMETERS * sizeof(fp));

	kernel_ecc(	timeinst,
				d_initvalu,
				d_finavalu,
				0,
				d_params);

	memcpy(finavalu, d_finavalu, EQUATIONS * sizeof(fp));
	memcpy(com, d_com, 3 * sizeof(fp));

	initvalu_offset_ecc = 0;
	initvalu_offset_Dyad = 46;
	initvalu_offset_SL = 61;
	initvalu_offset_Cyt = 76;

	kernel_fin(	initvalu,
				initvalu_offset_ecc,
				initvalu_offset_Dyad,
				initvalu_offset_SL,
				initvalu_offset_Cyt,
				parameter,
				finavalu,
				com[0],
				com[1],
				com[2]);

	for(i=0; i<EQUATIONS; i++){
		if (isnan(finavalu[i]) == 1){
			finavalu[i] = 0.0001;
		}
		else if (isinf(finavalu[i]) == 1){
			finavalu[i] = 0.0001;
		}
	}
}

