void master(fp timeinst, fp* initvalu, fp* parameter, fp* finavalu, fp* com, fp* d_initvalu, fp* d_finavalu, fp* d_params, fp* d_com) {
	int i;
	int initvalu_offset_ecc = 0, initvalu_offset_Dyad = 46, initvalu_offset_SL = 61, initvalu_offset_Cyt = 76;

	kernel_ecc(timeinst, d_initvalu, d_finavalu, initvalu_offset_ecc, d_params);
	kernel_cam(timeinst, d_initvalu, d_finavalu, initvalu_offset_Dyad, d_params, 1, d_com, 0, d_initvalu[36]);
	kernel_cam(timeinst, d_initvalu, d_finavalu, initvalu_offset_SL, d_params, 1, d_com, 1, d_initvalu[37]);
	kernel_cam(timeinst, d_initvalu, d_finavalu, initvalu_offset_Cyt, d_params, 1, d_com, 2, d_initvalu[38]);

	for(i=0; i<EQUATIONS; i++){ finavalu[i] = d_finavalu[i]; }
	com[0] = d_com[0]; com[1] = d_com[1]; com[2] = d_com[2];

	kernel_fin(initvalu, initvalu_offset_ecc, initvalu_offset_Dyad, initvalu_offset_SL, initvalu_offset_Cyt, parameter, finavalu, com[0], com[1], com[2]);

	for(i=0; i<EQUATIONS; i++){
		if (isnan(finavalu[i]) == 1){ finavalu[i] = 0.0001; }
		else if (isinf(finavalu[i]) == 1){ finavalu[i] = 0.0001; }
	}
}

