		kernel_cam_2(timeinst_temp, initvalu_temp, &finavalu_temp[j*EQUATIONS], 61, parameter, 1, com, 1, initvalu_temp[37]);
		kernel_cam_2(timeinst_temp, initvalu_temp, &finavalu_temp[j*EQUATIONS], 76, parameter, 1, com, 2, initvalu_temp[38]);
		kernel_fin_2(0, initvalu_temp, &finavalu_temp[j*EQUATIONS], 0, 46, 61, 76, parameter, com);

		for(i=0; i<EQUATIONS; i++){
			if (isnan(finavalu_temp[j*EQUATIONS+i]) == 1){ finavalu_temp[j*EQUATIONS+i] = 0.0001; }
			else if (isinf(finavalu_temp[j*EQUATIONS+i]) == 1){ finavalu_temp[j*EQUATIONS+i] = 0.0001; }
