int loadData(char *filename, Record **records, LatLong **locations, int *numRecords) {
    FILE   *flist, *fp;
    int    i=0;
    char dbname[64];
    int recNum=0;
    int initialCapacity = 10000;
    int currentCapacity = initialCapacity;

    *records = (Record *)malloc(sizeof(Record) * currentCapacity);
    *locations = (LatLong *)malloc(sizeof(LatLong) * currentCapacity);

    if (!*records || !*locations) {
        fprintf(stderr, "Initial memory allocation failed\n");
        exit(1);
    }

    flist = fopen(filename, "r");
    if (!flist) {
        fprintf(stderr, "Error opening filelist: %s\n", filename);
        exit(0);
    }

    while(!feof(flist)) {
        if(fscanf(flist, "%s\n", dbname) != 1) {
            if (!feof(flist)) {
                fprintf(stderr, "error reading filelist\n");
                exit(0);
            }
            break;
        }
        fp = fopen(dbname, "r");
        if(!fp) {
            printf("error opening a db\n");
            exit(1);
        }

        while(!feof(fp)){
            Record record;
            LatLong latLong;
            // Initialize recString to avoid garbage
            memset(record.recString, 0, REC_LENGTH);

            if (fgets(record.recString, 49, fp) == NULL) break;

            // Handle potential newline consumption logic from original
            int c = fgetc(fp);
            if (feof(fp)) {
                if (strlen(record.recString) == 0) break;
            }

            // Check capacity and expand if needed
            if (recNum >= currentCapacity) {
                currentCapacity *= 2;
                *records = (Record *)realloc(*records, sizeof(Record) * currentCapacity);
                *locations = (LatLong *)realloc(*locations, sizeof(LatLong) * currentCapacity);
                if (!*records || !*locations) {
                    fprintf(stderr, "Memory expansion failed\n");
                    exit(1);
                }
            }

            char substr[6];

            for(i=0;i<5;i++) {
                int idx = i + 28;
                if (idx < 49 && record.recString[idx] != '\0')
                    substr[i] = record.recString[idx];
                else
                    substr[i] = ' ';
            }
            substr[5] = '\0';
            latLong.lat = atof(substr);

            for(i=0;i<5;i++) {
                int idx = i + 33;
                if (idx < 49 && record.recString[idx] != '\0')
                    substr[i] = record.recString[idx];
                else
                    substr[i] = ' ';
            }
            substr[5] = '\0';
            latLong.lng = atof(substr);

            (*locations)[recNum] = latLong;
            (*records)[recNum] = record;
            recNum++;
        }
        fclose(fp);
    }
    fclose(flist);

    *numRecords = recNum;
    return recNum;
}

void findLowest(Record *records, float *distances, int numRecords, int topN){
  int i,j;
  float val;
  int minLoc;
  Record tempRec;
  float tempDist;

  for(i=0;i<topN;i++) {
    minLoc = i;
    for(j=i;j<numRecords;j++) {
      val = distances[j];
      if (val < distances[minLoc]) minLoc = j;
    }

    tempRec = records[i];
    records[i] = records[minLoc];
    records[minLoc] = tempRec;

    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;


    records[i].distance = distances[i];
  }
}

