void needle_shared_1(int* referrence, int* matrix_cuda, int cols, int penalty, int i, int block_width) {
    int bx = omp_get_thread_num();
    int tx = 0; // Simulating threadIdx.x = 0 for sequential execution within block logic, but we need to parallelize properly.
    // The CUDA code uses BLOCK_SIZE threads per block. 
    // To translate to OpenMP while preserving the algorithm's dependency structure (diagonal wavefront),
    // we must simulate the thread behavior or restructure. 
    // However, the prompt asks to preserve the algorithm. The CUDA algorithm relies on intra-block synchronization.
    // A direct translation of the GPU kernel logic to a single CPU thread per "block" is the safest way to preserve exact behavior
    // without rewriting the algorithm into a pure CPU parallel pattern (which might change results due to race conditions if not carefully done).
    // But wait, the CUDA code has `__shared__` memory and `__syncthreads`. This implies tight coupling.
    // Running this as a single thread per block iteration is correct for logic preservation.
    // The outer loop in runTest iterates over blocks. We will map that to OpenMP parallel regions if possible, 
    // but the dependency between blocks (i in runTest loop) suggests sequential execution of blocks is required by the algorithm design in the source.
    // Looking at runTest: 
    // for( int i = 1 ; i <= block_width ; i++){ ... needle_cuda_shared_1 ... }
    // The blocks in step 'i' depend on results from step 'i-1'? 
    // Actually, in Needleman-Wunsch, the diagonal bands can be processed in parallel if they don't depend on each other.
    // The original CUDA code launches multiple blocks in one kernel call? No, it loops and launches one kernel per 'i'.
    // Wait, the CUDA code: `for( int i = 1 ; i <= block_width ; i++){ dimGrid.x = i; ... kernel<<<dimGrid, dimBlock>>>... }`
    // This launches a kernel with `i` blocks. Inside the kernel, `bx` ranges from 0 to `i-1`.
    // The blocks within one kernel launch are independent? 
    // Let's look at indices: `b_index_y = i - 1 - bx`. As `bx` increases, `b_index_y` decreases.
    // These blocks correspond to different parts of the diagonal. They should be independent within the same kernel launch.
    // So we can parallelize the `bx` loop inside the kernel using OpenMP.

    // We will implement the kernel logic here, parallelized over `bx` (block index) using OpenMP.
    // Since the original code launches a kernel with `i` blocks, we parallelize over `bx` from 0 to `i-1`.

    // Note: The function is called inside a loop in runTest. 
    // We will put the OpenMP parallelization inside this function to simulate the GPU blocks.

    int num_blocks = i; // dimGrid.x was set to i

    #pragma omp parallel for
    for (int bx = 0; bx < num_blocks; bx++) {
        int tx_local; 
        // We need to simulate the BLOCK_SIZE threads. 
        // Since OpenMP parallelizes the blocks (bx), the threads within a block (tx) must be handled sequentially or with nested parallelism.
        // Given the small size of BLOCK_SIZE (16), sequential handling of tx within each bx is efficient and preserves sync logic easily.

        int b_index_x = bx;
        int b_index_y = i - 1 - bx;

        int index   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + 0 + ( cols + 1 ); // tx=0 base
        int index_n   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + 0 + ( 1 );
        int index_w   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + ( cols );
        int index_nw =  cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

        // Shared memory simulation
        int temp[BLOCK_SIZE+1][BLOCK_SIZE+1];
        int ref[BLOCK_SIZE][BLOCK_SIZE];

        // Simulate thread 0 action
        temp[0][0] = matrix_cuda[index_nw];

        // Load ref (all threads do this, but we do it sequentially for this block)
        for (int ty = 0; ty < BLOCK_SIZE; ty++) {
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                ref[ty][tx] = referrence[index + cols * ty + tx]; // index + cols*ty + tx corresponds to index + cols*ty when tx=0? 
                // Original: ref[ty][tx] = referrence[index + cols * ty]; 
                // Wait, original code: `index` depends on `tx`. 
                // `int index   = ... + tx + ( cols + 1 );`
                // So for each tx, index is different. 
                // In my sequential simulation, I need to loop tx.
            }
        }

        // Correcting ref loading logic for sequential simulation
        for (int ty = 0; ty < BLOCK_SIZE; ty++) {
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int current_index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( cols + 1 );
                ref[ty][tx] = referrence[current_index + cols * ty];
            }
        }

        // Simulate thread 0 action for temp[tx][0] where tx=0 -> temp[0][0] already done?
        // Original: if (tx == 0) temp[tx][0] = matrix_cuda[index_nw]; -> temp[0][0]
        // Already done.

        // Original: temp[tx + 1][0] = matrix_cuda[index_w + cols * tx];
        // This is done by each thread tx.
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int current_index_w = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + ( cols );
            // index_w does not depend on tx in the definition? 
            // `int index_w   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + ( cols );`
            // But access is `matrix_cuda[index_w + cols * tx]`
            temp[tx + 1][0] = matrix_cuda[current_index_w + cols * tx];
        }

        // Original: temp[0][tx + 1] = matrix_cuda[index_n];
        // `int index_n   = ... + tx + ( 1 );`
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int current_index_n = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( 1 );
            temp[0][tx + 1] = matrix_cuda[current_index_n];
        }

        // First diagonal pass
        for (int m = 0; m < BLOCK_SIZE; m++) {
            for (int tx = 0; tx <= m; tx++) {
                int t_index_x = tx + 1;
                int t_index_y = m - tx + 1;

                temp[t_index_y][t_index_x] = maximum( 
                    temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
                    temp[t_index_y][t_index_x-1]  - penalty, 
                    temp[t_index_y-1][t_index_x]  - penalty);
            }
        }

        // Second diagonal pass
        for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
            for (int tx = 0; tx <= m; tx++) {
                int t_index_x = tx + BLOCK_SIZE - m;
                int t_index_y = BLOCK_SIZE - tx;

                temp[t_index_y][t_index_x] = maximum( 
                    temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
                    temp[t_index_y][t_index_x-1]  - penalty, 
                    temp[t_index_y-1][t_index_x]  - penalty);
            }
        }

        // Write back
        for (int ty = 0; ty < BLOCK_SIZE; ty++) {
            int current_index_write = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + 0 + ( cols + 1 ); // tx=0 base?
            // Original: matrix_cuda[index + ty * cols] = temp[ty+1][tx+1];
            // Here index depends on tx. We are writing for all tx.
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int current_index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( cols + 1 );
                matrix_cuda[current_index + ty * cols] = temp[ty+1][tx+1];
            }
        }
    }
}

void needle_shared_2(int* referrence, int* matrix_cuda, int cols, int penalty, int i, int block_width) {
    int num_blocks = block_width - i + 1; // Based on loop in runTest: i from block_width-1 to 1. 
    // Wait, runTest loop: `for( int i = block_width - 1  ; i >= 1 ; i--){ dimGrid.x = i; ... }`
    // So num_blocks = i.
    num_blocks = i;

    #pragma omp parallel for
    for (int bx = 0; bx < num_blocks; bx++) {
        int b_index_x = bx + block_width - i;
        int b_index_y = block_width - bx - 1;

        int temp[BLOCK_SIZE+1][BLOCK_SIZE+1];
        int ref[BLOCK_SIZE][BLOCK_SIZE];

        // Load ref
        for (int ty = 0; ty < BLOCK_SIZE; ty++) {
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int current_index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( cols + 1 );
                ref[ty][tx] = referrence[current_index + cols * ty];
            }
        }

        // Init temp
        int index_nw = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;
        temp[0][0] = matrix_cuda[index_nw];

        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int current_index_w = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + ( cols );
            temp[tx + 1][0] = matrix_cuda[current_index_w + cols * tx];
        }

        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int current_index_n = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( 1 );
            temp[0][tx + 1] = matrix_cuda[current_index_n];
        }

        // First pass
        for (int m = 0; m < BLOCK_SIZE; m++) {
            for (int tx = 0; tx <= m; tx++) {
                int t_index_x = tx + 1;
                int t_index_y = m - tx + 1;
                temp[t_index_y][t_index_x] = maximum( 
                    temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
                    temp[t_index_y][t_index_x-1]  - penalty, 
                    temp[t_index_y-1][t_index_x]  - penalty);
            }
        }

        // Second pass
        for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
            for (int tx = 0; tx <= m; tx++) {
                int t_index_x = tx + BLOCK_SIZE - m;
                int t_index_y = BLOCK_SIZE - tx;
                temp[t_index_y][t_index_x] = maximum( 
                    temp[t_index_y-1][t_index_x-1] + ref[t_index_y-1][t_index_x-1],
                    temp[t_index_y][t_index_x-1]  - penalty, 
                    temp[t_index_y-1][t_index_x]  - penalty);
            }
        }

        // Write back
        for (int ty = 0; ty < BLOCK_SIZE; ty++) {
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                int current_index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + ( cols + 1 );
                matrix_cuda[current_index + ty * cols] = temp[ty+1][tx+1];
            }
        }
    }
}

