void runTest( int argc, char** argv) 
{
    int max_rows, max_cols, penalty;
    int *input_itemsets, *output_itemsets, *referrence;
	int size;



	if (argc == 3)
	{
		max_rows = atoi(argv[1]);
		max_cols = atoi(argv[1]);
		penalty = atoi(argv[2]);
	}
    else{
	usage(argc, argv);
    }

	if(atoi(argv[1])%16!=0){
	fprintf(stderr,"The dimension values must be a multiple of 16\n");
	exit(1);
	}


	max_rows = max_rows + 1;
	max_cols = max_cols + 1;
	referrence = (int *)malloc( max_rows * max_cols * sizeof(int) );
    input_itemsets = (int *)malloc( max_rows * max_cols * sizeof(int) );
	output_itemsets = (int *)malloc( max_rows * max_cols * sizeof(int) );


	if (!input_itemsets)
		fprintf(stderr, "error: can not allocate memory");

    srand ( 7 );


    for (int i = 0 ; i < max_cols; i++){
		for (int j = 0 ; j < max_rows; j++){
			input_itemsets[i*max_cols+j] = 0;
		}
	}

	printf("Start Needleman-Wunsch\n");

	for( int i=1; i< max_rows ; i++){    
       input_itemsets[i*max_cols] = rand() % 10 + 1;
	}
    for( int j=1; j< max_cols ; j++){    
       input_itemsets[j] = rand() % 10 + 1;
	}


	for (int i = 1 ; i < max_cols; i++){
		for (int j = 1 ; j < max_rows; j++){
		referrence[i*max_cols+j] = blosum62[input_itemsets[i*max_cols]][input_itemsets[j]];
		}
	}

    for( int i = 1; i< max_rows ; i++)
       input_itemsets[i*max_cols] = -i * penalty;
	for( int j = 1; j< max_cols ; j++)
       input_itemsets[j] = -j * penalty;


    size = max_cols * max_rows;

    int block_width = ( max_cols - 1 )/BLOCK_SIZE;

#ifdef  TIMING
  gettimeofday(&tv_kernel_start, NULL);
#endif

	printf("Processing top-left matrix\n");

	for( int i = 1 ; i <= block_width ; i++){
        // Parallelize over blocks (bx) and threads (tx) within the block logic
        // Since the original CUDA code launches a kernel where each thread does work,
        // we parallelize the outer loop over bx, and inside each thread we simulate the tx loop.
        // However, the original kernel uses shared memory which requires cooperation between threads in a block.
        // To preserve the algorithm exactly as a sequential simulation of the block:
        // We iterate bx sequentially (as the original loop does), and inside, we parallelize over tx?
        // No, the original CUDA loop: for i... { launch kernel with dimGrid.x=i }.
        // The kernel runs for all blocks in dimGrid simultaneously.
        // But here, the loop `for( int i = 1 ; i <= block_width ; i++)` sets dimGrid.x = i.
        // This means for a given `i`, we run `i` blocks.
        // Inside the kernel, each block is independent.
        // So we can parallelize over bx (0 to i-1).
        // Inside each block, the threads cooperate via shared memory.
        // In OpenMP, we can treat each block as a task or just iterate bx in parallel.
        // But the shared memory logic inside `needle_shared_1` assumes all threads in the block run together.
        // If we parallelize over bx, each thread in the OpenMP team will handle one block (bx).
        // Inside that block, we need to simulate the BLOCK_SIZE threads.
        // We can do this by having the OpenMP thread loop over tx from 0 to BLOCK_SIZE-1 sequentially?
        // No, that would be slow.
        // Better: The original CUDA kernel runs BLOCK_SIZE threads per block.
        // We can map OpenMP threads to CUDA threads.
        // But the dependency is within the block.
        // Let's stick to the structure: Outer loop `i` is sequential (as in source).
        // Inner loop `bx` (blocks) can be parallel.
        // Inside each block, we need to execute the logic for all `tx`.
        // Since the block logic relies on synchronization, we must execute the block logic as a unit.
        // But the block logic itself is parallel over `tx`.
        // So for each block `bx`, we spawn a parallel region for `tx`? That's heavy.
        // Alternatively, we assume the OpenMP parallelism is at the `bx` level, and inside we sequentialize `tx`.
        // But that changes performance characteristics significantly.
        // However, the prompt asks to preserve the algorithm. The algorithm's correctness depends on the shared memory sync.
        // If we sequentialize `tx` inside a block, the result is the same because the sync points are just ordering constraints.
        // If we run `tx` sequentially, the `__syncthreads()` are naturally satisfied.
        // So: Parallelize over `bx`. Inside, loop `tx` from 0 to BLOCK_SIZE-1 sequentially.
        // Wait, the original code: `dimGrid.x = i`. So blocks are 0..i-1.

        #pragma omp parallel for
        for(int bx = 0; bx < i; bx++) {
            // Simulate the block: run all tx sequentially for this block
            for(int tx = 0; tx < BLOCK_SIZE; tx++) {
                needle_shared_1(referrence, input_itemsets, max_cols, penalty, i, block_width, bx, tx);
            }
        }
	}
	printf("Processing bottom-right matrix\n");

	for( int i = block_width - 1  ; i >= 1 ; i--){
        #pragma omp parallel for
        for(int bx = 0; bx < i; bx++) {
            for(int tx = 0; tx < BLOCK_SIZE; tx++) {
                needle_shared_2(referrence, input_itemsets, max_cols, penalty, i, block_width, bx, tx);
            }
        }
	}

#ifdef  TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    // Copy is implicit since we are using the same array
    // cudaMemcpy(output_itemsets, matrix_cuda, sizeof(int) * size, cudaMemcpyDeviceToHost);
    // input_itemsets is the matrix_cuda in our translation
    // output_itemsets is allocated separately, so we copy
    memcpy(output_itemsets, input_itemsets, sizeof(int) * size);

#ifdef TRACEBACK

	FILE *fpo = fopen("result.txt","w");
	fprintf(fpo, "print traceback value GPU:\n");

	for (int i = max_rows - 2,  j = max_rows - 2; i>=0, j>=0;){
		int nw, n, w, traceback;
		if ( i == max_rows - 2 && j == max_rows - 2 )
			fprintf(fpo, "%d ", output_itemsets[ i * max_cols + j]); 
		if ( i == 0 && j == 0 )
           break;
		if ( i > 0 && j > 0 ){
			nw = output_itemsets[(i - 1) * max_cols + j - 1];
		    w  = output_itemsets[ i * max_cols + j - 1 ];
            n  = output_itemsets[(i - 1) * max_cols + j];
		}
		else if ( i == 0 ){
		    nw = n = LIMIT;
		    w  = output_itemsets[ i * max_cols + j - 1 ];
		}
		else if ( j == 0 ){
		    nw = w = LIMIT;
            n  = output_itemsets[(i - 1) * max_cols + j];
		}
		else{
		}


		int new_nw, new_w, new_n;
		new_nw = nw + referrence[i * max_cols + j];
		new_w = w - penalty;
		new_n = n - penalty;

		traceback = maximum(new_nw, new_w, new_n);
		if(traceback == new_nw)
			traceback = nw;
		if(traceback == new_w)
			traceback = w;
		if(traceback == new_n)
            traceback = n;

		fprintf(fpo, "%d ", traceback);

		if(traceback == nw )
		{i--; j--; continue;}

        else if(traceback == w )
		{j--; continue;}

        else if(traceback == n )
		{i--; continue;}

		else
		;
	}

	fclose(fpo);

#endif

	free(referrence);
	free(input_itemsets);
	free(output_itemsets);

#ifdef  TIMING
    printf("Exec: %f\n", kernel_time);
#endif
}

