void needle_shared_1(int* referrence, int* matrix_cuda, int cols, int penalty, int i, int block_width) {
    int bx = omp_get_thread_num();
    int tx = 0; // Simulating single thread per block logic for translation, but we need to parallelize properly

    // In OpenMP, we simulate the block structure by iterating over blocks
    // The original CUDA code runs one block per invocation in the loop, but here we parallelize the blocks
    // However, the original loop iterates i from 1 to block_width, launching i blocks.
    // To maintain exact algorithmic behavior, we must simulate the block execution sequentially or carefully parallelize.
    // Given the dependency structure (diagonal waves), the original CUDA code launches multiple blocks per step.
    // We will parallelize the outer loop over blocks within each step.

    int b_index_x = bx;
    int b_index_y = i - 1 - bx;

    if (b_index_x < 0 || b_index_y < 0 || b_index_x >= i || b_index_y >= i) return;

    int index   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (cols + 1);
    int index_n   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + tx + (1);
    int index_w   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + (cols);
    int index_nw =  cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    // Shared memory simulation using local arrays
    int temp[BLOCK_SIZE+1][BLOCK_SIZE+1];
    int ref[BLOCK_SIZE][BLOCK_SIZE];

    // Since we are translating to OpenMP and each "block" in CUDA corresponds to a thread or group of threads
    // We need to restructure. The original CUDA code has BLOCK_SIZE threads per block.
    // Here we will use a nested loop approach to simulate the thread behavior within a block.

    // We must iterate over tx (thread index) inside this function if we want to simulate one block
    // But to parallelize across blocks, we assume this function is called per block? 
    // No, the original code launches <<<dimGrid, dimBlock>>> where dimGrid.x = i.
    // So there are 'i' blocks. Each block has BLOCK_SIZE threads.
    // In OpenMP, we can parallelize the blocks (outer loop) and then use a loop for threads inside.

    // However, the provided translation target is a single C++ file. 
    // We will restructure the logic to run the block logic in a parallel region.

    // Let's rewrite the strategy:
    // The original runTest loops i from 1 to block_width.
    // Inside, it launches i blocks.
    // We will keep the loop over i, but parallelize the execution of the 'i' blocks using OpenMP.
    // Inside each block, we simulate the BLOCK_SIZE threads using a loop.

    // This function is now designed to be called once per block, with tx ranging from 0 to BLOCK_SIZE-1
    // But OpenMP doesn't have native "blocks". We will handle the block iteration in runTest.

    // Actually, to make it work efficiently and correctly in OpenMP:
    // We will modify runTest to have a parallel region over the blocks for each step i.
    // And this function will be the body executed by each "block" (which is now a team of threads? No).
    // CUDA: i blocks, each with BLOCK_SIZE threads.
    // OpenMP: We can have i teams? No, standard OpenMP has one team.
    // We can map each CUDA block to a set of iterations in a loop handled by threads.
    // But the synchronization (__syncthreads) is within a block.
    // So, each CUDA block must be handled by a single thread or a coordinated group.
    // Given the complexity of simulating __syncthreads across OpenMP threads without nested parallelism (which is tricky),
    // and since BLOCK_SIZE is small (16), we can simulate the block's threads sequentially within one OpenMP thread?
    // That would be slow.
    // Better approach: Treat each CUDA block as a unit of work. Inside that unit, we simulate the threads sequentially?
    // Or, we restructure the algorithm to not rely on block-level shared memory?
    // The algorithm uses shared memory for temp and ref.
    // If we assign one OpenMP thread to one CUDA block, and inside that thread we loop over tx (0..BLOCK_SIZE-1) to simulate the threads,
    // then __syncthreads() becomes trivial (just sequential execution).
    // This preserves correctness and is easy to implement. The parallelism comes from multiple blocks (i blocks) running on different OpenMP threads.

    // So, in runTest, we will have #pragma omp parallel for for the blocks.
    // And this function will be called once per block, with a specific block index.
    // But the original CUDA kernel uses threadIdx.x.
    // So we need to pass the block index to this function, and then inside, we loop over tx.

    // Let's adjust: This function will now represent the work of ONE CUDA block.
    // It will internally loop over tx from 0 to BLOCK_SIZE-1 to simulate the threads.
    // The caller (runTest) will parallelize over the blocks.

    // Wait, the original kernel code uses `tx` (threadIdx.x) directly.
    // So we need to simulate all threads in the block.

    int local_temp[BLOCK_SIZE+1][BLOCK_SIZE+1];
    int local_ref[BLOCK_SIZE][BLOCK_SIZE];

    // Simulate all threads in the block sequentially to handle shared memory dependencies
    // First, initialize ref and boundary conditions which depend on tx

    // We need to store values that depend on tx. 
    // Since we are simulating sequentially, we can just compute for each tx.

    // However, the original code has __syncthreads() which implies all threads must finish before next step.
    // Sequential simulation naturally satisfies this.

    // Let's compute the data for all tx first for the initialization parts.

    // Load ref for all tx and ty
    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int cur_tx = 0; cur_tx < BLOCK_SIZE; cur_tx++) {
            int cur_index = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + cur_tx + (cols + 1);
            local_ref[ty][cur_tx] = referrence[cur_index + cols * ty];
        }
    }

    // Initialize temp[tx][0] for tx=0 only in original code
    // In original: if (tx == 0) temp[tx][0] = matrix_cuda[index_nw];
    // index_nw is constant for the block.
    int index_nw_val = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;
    local_temp[0][0] = matrix_cuda[index_nw_val];

    // Initialize temp[tx+1][0] for all tx
    // Original: temp[tx + 1][0] = matrix_cuda[index_w + cols * tx];
    // index_w depends on block, but the access varies by tx.
    int index_w_base = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + (cols);
    for (int cur_tx = 0; cur_tx < BLOCK_SIZE; cur_tx++) {
        local_temp[cur_tx + 1][0] = matrix_cuda[index_w_base + cols * cur_tx];
    }

    // Initialize temp[0][tx+1] for all tx
    // Original: temp[0][tx + 1] = matrix_cuda[index_n];
    int index_n_base = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + (1);
    for (int cur_tx = 0; cur_tx < BLOCK_SIZE; cur_tx++) {
        local_temp[0][cur_tx + 1] = matrix_cuda[index_n_base + cur_tx]; // index_n + tx? 
        // Original: index_n = ... + tx + 1. 
        // Wait, original: index_n = ... + tx + (1). 
        // So matrix_cuda[index_n] uses the specific tx.
        // My index_n_base calculation: ... + (1). Then we need to add tx.
        // Correct: index_n = base + tx.
        local_temp[0][cur_tx + 1] = matrix_cuda[index_n_base + cur_tx];
    }

    // Now simulate the first loop over m
    for (int m = 0; m < BLOCK_SIZE; m++) {
        for (int cur_tx = 0; cur_tx <= m; cur_tx++) {
            int t_index_x = cur_tx + 1;
            int t_index_y = m - cur_tx + 1;

            local_temp[t_index_y][t_index_x] = maximum(
                local_temp[t_index_y-1][t_index_x-1] + local_ref[t_index_y-1][t_index_x-1],
                local_temp[t_index_y][t_index_x-1] - penalty,
                local_temp[t_index_y-1][t_index_x] - penalty
            );
        }
        // __syncthreads() implied by sequential execution
    }

    // Simulate the second loop over m
    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        for (int cur_tx = 0; cur_tx <= m; cur_tx++) {
            int t_index_x = cur_tx + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - cur_tx;

            local_temp[t_index_y][t_index_x] = maximum(
                local_temp[t_index_y-1][t_index_x-1] + local_ref[t_index_y-1][t_index_x-1],
                local_temp[t_index_y][t_index_x-1] - penalty,
                local_temp[t_index_y-1][t_index_x] - penalty
            );
        }
    }

    // Write back results for all ty and tx
    // Original: for (int ty = 0; ty < BLOCK_SIZE; ty++) matrix_cuda[index + ty * cols] = temp[ty+1][tx+1];
    // This is done per thread (tx). So we need to loop over tx and ty.
    for (int cur_tx = 0; cur_tx < BLOCK_SIZE; cur_tx++) {
        int base_idx = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + cur_tx + (cols + 1);
        for (int ty = 0; ty < BLOCK_SIZE; ty++) {
            matrix_cuda[base_idx + ty * cols] = local_temp[ty+1][cur_tx+1];
        }
    }
}

void needle_shared_2(int* referrence, int* matrix_cuda, int cols, int penalty, int i, int block_width) {
    int bx = omp_get_thread_num();

    int b_index_x = bx + block_width - i;
    int b_index_y = block_width - bx - 1;

    if (b_index_x < 0 || b_index_y < 0 || bx >= i) return;

    int index   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + (cols + 1); // tx added later
    int index_n   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + (1);
    int index_w   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + (cols);
    int index_nw =  cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    int local_temp[BLOCK_SIZE+1][BLOCK_SIZE+1];
    int local_ref[BLOCK_SIZE][BLOCK_SIZE];

    // Load ref
    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int cur_tx = 0; cur_tx < BLOCK_SIZE; cur_tx++) {
            local_ref[ty][cur_tx] = referrence[index + cur_tx + cols * ty];
        }
    }

    // Init temp[tx][0] for tx=0
    local_temp[0][0] = matrix_cuda[index_nw];

    // Init temp[tx+1][0]
    for (int cur_tx = 0; cur_tx < BLOCK_SIZE; cur_tx++) {
        local_temp[cur_tx + 1][0] = matrix_cuda[index_w + cols * cur_tx];
    }

    // Init temp[0][tx+1]
    for (int cur_tx = 0; cur_tx < BLOCK_SIZE; cur_tx++) {
        local_temp[0][cur_tx + 1] = matrix_cuda[index_n + cur_tx];
    }

    // First loop
    for (int m = 0; m < BLOCK_SIZE; m++) {
        for (int cur_tx = 0; cur_tx <= m; cur_tx++) {
            int t_index_x = cur_tx + 1;
            int t_index_y = m - cur_tx + 1;
            local_temp[t_index_y][t_index_x] = maximum(
                local_temp[t_index_y-1][t_index_x-1] + local_ref[t_index_y-1][t_index_x-1],
                local_temp[t_index_y][t_index_x-1] - penalty,
                local_temp[t_index_y-1][t_index_x] - penalty
            );
        }
    }

    // Second loop
    for (int m = BLOCK_SIZE - 2; m >= 0; m--) {
        for (int cur_tx = 0; cur_tx <= m; cur_tx++) {
            int t_index_x = cur_tx + BLOCK_SIZE - m;
            int t_index_y = BLOCK_SIZE - cur_tx;
            local_temp[t_index_y][t_index_x] = maximum(
                local_temp[t_index_y-1][t_index_x-1] + local_ref[t_index_y-1][t_index_x-1],
                local_temp[t_index_y][t_index_x-1] - penalty,
                local_temp[t_index_y-1][t_index_x] - penalty
            );
        }
    }

    // Write back
    for (int cur_tx = 0; cur_tx < BLOCK_SIZE; cur_tx++) {
        int base_idx = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + cur_tx + (cols + 1);
        for (int ty = 0; ty < BLOCK_SIZE; ty++) {
            matrix_cuda[base_idx + ty * cols] = local_temp[ty+1][cur_tx+1];
        }
    }
}

