#define IN_RANGE(x, min, max)   ((x)>= (min) && (x)<= (max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<= (b) ? (a) : (b))

int calc_path(int *gpuWall, int *gpuResult[2], int rows, int cols, \
	 int pyramid_height, int blockCols, int borderCols)
{

        int src = 1, dst = 0;
	for (int t = 0; t < rows-1; t+=pyramid_height) {
            int temp = src;
            src = dst;
            dst = temp;

            int iteration = MIN(pyramid_height, rows-t-1);
            int small_block_cols = BLOCK_SIZE-iteration*HALO*2;
            int *gpuSrc = gpuResult[src];
            int *gpuResults = gpuResult[dst];

            #pragma omp parallel for schedule(static)
            for (int bx = 0; bx < blockCols; bx++) {
                int blkX = small_block_cols*bx-borderCols;
                int blkXmax = blkX+BLOCK_SIZE-1;

                int validXmin_global = (blkX < 0) ? -blkX : 0;
                int validXmax_global = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

                #pragma omp parallel for schedule(static)
                for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                    int xidx = blkX+tx;

                    int W = tx-1;
                    int E = tx+1;

                    int validXmin = validXmin_global;
                    int validXmax = validXmax_global;

                    W = (W < validXmin) ? validXmin : W;
                    E = (E > validXmax) ? validXmax : E;

                    bool isValid = IN_RANGE(tx, validXmin, validXmax);

                    int prev[BLOCK_SIZE];
                    int result_local[BLOCK_SIZE];

                    if(IN_RANGE(xidx, 0, cols-1)){
                        prev[tx] = gpuSrc[xidx];
                    }

                    bool computed;
                    for (int i=0; i<iteration ; i++){ 
                        computed = false;
                        if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid){
                            computed = true;
                            int left = prev[W];
                            int up = prev[tx];
                            int right = prev[E];
                            int shortest = MIN(left, up);
                            shortest = MIN(shortest, right);
                            int index = cols*(t+i)+xidx;
                            result_local[tx] = shortest + gpuWall[index];
                        }

                        if(i==iteration-1)
                            break;
                        if(computed)	 
                            prev[tx]= result_local[tx];
                    }

                    if (computed && IN_RANGE(xidx, 0, cols-1)){
                        gpuResults[xidx]=result_local[tx];		
                    }
                }
            }
	}
        return dst;
}

