#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

void dynproc_kernel(
                int iteration, 
                int *gpuWall,
                int *gpuSrc,
                int *gpuResults,
                int cols, 
                int rows,
                int startStep,
                int border)
{
    int blockCols = (cols + border * 2 + BLOCK_SIZE - 1) / BLOCK_SIZE; 

    #pragma omp parallel
    {
        int prev[BLOCK_SIZE];
        int result_buf[BLOCK_SIZE];
        bool computed_flag[BLOCK_SIZE];

        int bx = omp_get_thread_num();
        int num_threads = omp_get_num_threads();

        if (bx < blockCols) {
            int tx;
            int small_block_cols = BLOCK_SIZE - iteration * HALO * 2;
            int blkX = small_block_cols * bx - border;
            int blkXmax = blkX + BLOCK_SIZE - 1;

            for (tx = 0; tx < BLOCK_SIZE; tx++) {
                int xidx = blkX + tx;
                if (IN_RANGE(xidx, 0, cols-1)) {
                    prev[tx] = gpuSrc[xidx];
                } else {
                    prev[tx] = 0;
                }
                computed_flag[tx] = false;
            }

            for (int i = 0; i < iteration; i++) { 
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    computed_flag[tx] = false;

                    int validXmin = (blkX < 0) ? -blkX : 0;
                    int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

                    int W = tx-1;
                    int E = tx+1;

                    W = (validXmin > W) ? validXmin : W;
                    E = (E > validXmax) ? validXmax : E;

                    bool isValid = IN_RANGE(tx, validXmin, validXmax);

                    if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid){
                        computed_flag[tx] = true;
                        int left = prev[W];
                        int up = prev[tx];
                        int right = prev[E];
                        int shortest = MIN(left, up);
                        shortest = MIN(shortest, right);
                        int xidx = blkX + tx;
                        int index = cols*(startStep+i)+xidx;
                        result_buf[tx] = shortest + gpuWall[index];
                    }
                }

                if(iteration-1 == i)
                    break;

                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    if(computed_flag[tx])
                        prev[tx] = result_buf[tx];
                }
            }

            for (tx = 0; tx < BLOCK_SIZE; tx++) {
                if (computed_flag[tx]) {
                    int xidx = blkX + tx;
                    if (IN_RANGE(xidx, 0, cols-1)) {
                        gpuResults[xidx] = result_buf[tx];
                    }
                }
            }
        }
    }
}

