float d_dist(int p1, int p2, int num, int dim, float *coord_d)
{
	float retval = 0.0;
	for(int i = 0; dim > i; i++){
		float tmp = coord_d[(i*num)+p1] - coord_d[(i*num)+p2];
		retval = retval + (tmp * tmp);
	}
	return retval;
}

