{
	center_table_d = (int*) malloc(num * sizeof(int));
	switch_membership_d = (bool*) malloc(num * sizeof(bool));
	p = (Point*) malloc(num * sizeof(Point));
	coord_d = (float*) malloc(num * dim * sizeof(float));
}

